[BusinessEvents(classStr(InventSumUpdateContract),
'Inventory summary update',
    'Triggers whenever an on-hand inventory record is created or updated',
    ModuleAxapta::Inventory)] // <-- Fixed Enum Value
public final class InventSumUpdateBusinessEvent extends BusinessEventsBase
{
    private InventSum inventSumRecord;

}

Method.Source:
public static InventSumUpdateBusinessEvent newFromInventSum(InventSum _inventSum)
{
    InventSumUpdateBusinessEvent businessEvent = new InventSumUpdateBusinessEvent();
    businessEvent.parmInventSum(_inventSum);
    return businessEvent;
}

public InventSum parmInventSum(InventSum _inventSum = inventSumRecord)
{
    inventSumRecord = _inventSum;
    return inventSumRecord;
}
